const { EventEmitter } = require('events');

const app = express();
app.use(bodyParser.json({ limit: '1mb' }));

class FakeLLM {
  async generateCode(prompt) {
    const p = String(prompt || '').toLowerCase();

    if (p.includes('list files')) {
      return `
        const fs = require('fs');
        const path = require('path');
        const dir = input.dir || process.cwd();
        output = fs.readdirSync(path.resolve(dir));
      `;
    }

    if (p.includes('current time')) {
      return `
        output = { now: new Date().toISOString() };
      `;
    }

    return `
      output = {
        message: "Generated code executed",
        prompt: input.prompt || null,
        receivedInput: input
      };
    `;
  }
}

const llm = new FakeLLM();
const jobs = new EventEmitter();

function validatePrompt(prompt) {
  if (typeof prompt !== 'string' || !prompt.trim()) {
    throw new Error('prompt must be a non-empty string');
  }
  if (prompt.length > 5000) {
    throw new Error('prompt too long');
  }
}

function executeGeneratedCode(code, input = {}) {
  const sandbox = {
    input,
    output: null,
    console: {
      log: (...args) => {},
      error: (...args) => {}
    }
  };

  vm.createContext(sandbox);

  const script = new vm.Script(`
    "use strict";
    ${code}
  `);

  script.runInContext(sandbox, { timeout: 1000 });

  return sandbox.output;
}

